// ‚îÄ‚îÄ DIAGNOSTIC BUSINESS (recrutement / ventes / r√©seaux) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
async function genererDiagBusiness(type, reponses, nomClient) {
  const typeLabels = {
    pasrecruiter: "blocage en recrutement MLM/VDI",
    pasvendre: "blocage en ventes de produits Mihi",
    reseaux: "inefficacit√© des r√©seaux sociaux pour son activit√© Mihi",
    chargementale: "√©quilibre vie pro/perso et charge mentale",
    valeurmarche: "valeur professionnelle et manque √Ý gagner",
    entrepreneuriat: "profil entrepreneurial et potentiel",
    complementrevenu: "objectif de compl√©ment de revenu",
  };
  const reponsesText = Object.entries(reponses||{})
    .filter(([k]) => k !== "_contact")
    .map(([k,v]) => `- ${k}: ${v}`).join("\n") || "Pas de r√©ponses";

  const prompt = `Tu es coach en d√©veloppement d'activit√© MLM/VDI pour la marque Mihi (cosm√©tiques et bien-√™tre naturels).
${nomClient||"Une distributrice"} a rempli un diagnostic sur son ${typeLabels[type]}.

R√©ponses au questionnaire :
${reponsesText}

G√©n√®re un plan d'action personnalis√© en JSON avec cette structure exacte (ne mets rien d'autre que le JSON) :
{
  "diagnostic": "2-3 phrases qui r√©sument ce que tu observes dans ses r√©ponses, sans la juger",
  "points_forts": ["point fort 1", "point fort 2"],
  "blocages": ["blocage identifi√© 1", "blocage identifi√© 2", "blocage identifi√© 3"],
  "plan_action": [
    {"priorite": "üî• Imm√©diat", "action": "action concr√®te √Ý faire cette semaine", "pourquoi": "explication courte"},
    {"priorite": "üìÖ Cette p√©riode", "action": "action √Ý mettre en place sur 21 jours", "pourquoi": "explication courte"},
    {"priorite": "üöÄ Long terme", "action": "habitude √Ý ancrer sur le long terme", "pourquoi": "explication courte"}
  ],
  "message_encouragement": "1 phrase personnalis√©e d'encouragement direct, chaleureuse et motivante"
}`;

  try{
    const response = await fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",
      headers:{
        "Content-Type":"application/json",
        "x-api-key":"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",
        "anthropic-version":"2023-06-01",
        "anthropic-dangerous-direct-browser-access":"true",
      },
      body:JSON.stringify({model:"claude-sonnet-4-6",max_tokens:4000,messages:[{role:"user",content:prompt}]}),
    });
    const data = await response.json();
    if(data.error) throw new Error(data.error.message);
    const text = data.content?.map(i=>i.text||"").join("")||"";
    const clean = text.replace(/```json|```/g,"").trim();
    const parsed = JSON.parse(clean);
    return {...parsed, kind:"business", type};
  }catch(e){
    throw e;
  }
}

// ‚îÄ‚îÄ DIAGNOSTIC IA ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
// ‚îÄ‚îÄ DIAGNOSTIC IA ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
// ‚îÄ‚îÄ DIAGNOSTIC IA ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
// ‚îÄ‚îÄ DIAGNOSTIC IA ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
async function genererOrdonnanceIA(type, reponses, nomClient) {
  // Types business (pas de catalogue produits)
  const typesBusiness = ["pasrecruiter","pasvendre","reseaux","chargementale","valeurmarche","entrepreneuriat","complementrevenu"];
  if(typesBusiness.includes(type)){
    return genererDiagBusiness(type, reponses, nomClient);
  }

  // Charger les notes admin si elles existent
  let notesAdmin = "";
  try {
    const snap = await getDoc(doc(db,"admin","diag_notes"));
    if(snap.exists() && snap.data()[type]) notesAdmin = snap.data()[type];
  } catch {}

  // Charger le catalogue r√©el des produits Mihi selon le type
  let catalogueText = "";
  try {
    const catSnap = await getDoc(doc(db,"admin","catalogue_mihi"));
    if(catSnap.exists()){
      const cat = catSnap.data();
      let cles = [];
      if(type==="skincare") cles=["face"];
      else if(type==="cheveux") cles=["hair"];
      else if(type==="sante"||type==="silhouette"||type==="detox"||type==="antiage") cles=["health"];
      else if(type==="makeup") cles=["makeup","face"];
      else if(type==="peaucorps") cles=["corps","health"];
      else cles=["face","corps","hair","makeup","health"];
      let produits=[];
      cles.forEach(cle=>{ produits=[...produits,...(cat[cle]||[])]; });
      if(produits.length>25) produits=produits.slice(0,25);
      catalogueText = produits.map(p=>`${p.nom} ‚Äî ${p.prix}‚Ç¨`).join("\n");
    }
  } catch (e) { console.error("Erreur chargement catalogue:", e); }

  const typeLabel =
    type==="skincare"?"soin visage/peau":
    type==="cheveux"?"soin capillaire":
    type==="makeup"?"maquillage et couleurs":
    type==="peaucorps"?"soin de la peau du corps":
    "sant√© et compl√©ments alimentaires";
  
  const reponsesText = Object.entries(reponses||{})
    .filter(([k]) => k !== "_contact")
    .map(([k,v]) => `- ${k}: ${v}`).join("\n") || "Pas de r√©ponses d√©taill√©es";
  
  const prompt = `Experte beaut√© MIHI. Diagnostic ${typeLabel} pour ${nomClient||"Cliente"}.
R√©ponses: ${reponsesText}
Catalogue: ${catalogueText}
${notesAdmin?`Notes: ${notesAdmin}`:""}

3 packs UNIQUEMENT avec les produits du catalogue. Traduis les noms en fran√ßais. JSON strict:
{"introduction":"2 phrases personnalis√©es","budget":{"total":"X‚Ç¨","produits":[{"nom":"Nom FR","prix":"X‚Ç¨","usage":"Matin/Soir","benefice":"1 phrase","comment":"1 geste concret ex: appliquer sur visage humide en cercles"}],"routine":"Routine matin : √©tape1 ‚Üí √©tape2. Routine soir : √©tape1 ‚Üí √©tape2"},"bestseller":{"total":"X‚Ç¨","produits":[{"nom":"Nom FR","prix":"X‚Ç¨","usage":"Matin/Soir","benefice":"1 phrase","comment":"1 geste concret"}],"routine":"Routine matin : √©tape1 ‚Üí √©tape2. Routine soir : √©tape1 ‚Üí √©tape2"},"premium":{"total":"X‚Ç¨","produits":[{"nom":"Nom FR","prix":"X‚Ç¨","usage":"Matin/Soir","benefice":"1 phrase","comment":"1 geste concret"}],"routine":"Routine matin : √©tape1 ‚Üí √©tape2. Routine soir : √©tape1 ‚Üí √©tape2"},"conseil":"1 conseil final personnalis√© li√© au profil"}

R√®gles: budget=1-2 produits, bestseller=3 produits, premium=4-5 produits. Prix exacts du catalogue.`;

  try {
    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": "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",
        "anthropic-version": "2023-06-01",
        "anthropic-dangerous-direct-browser-access": "true"
      },
      body: JSON.stringify({
        model: "claude-sonnet-4-6",
        max_tokens: 8000,
        messages: [{ role: "user", content: prompt }]
      })
    });

    const data = await response.json();

    if(data.error){
      console.error("Erreur API Claude:", data.error);
      throw new Error("API: " + (data.error.message || JSON.stringify(data.error)));
    }

    const text = data.content?.map(i => i.text || "").join("") || "";
    console.log("=== R√âPONSE IA BRUTE ===", text);
    console.log("=== LONGUEUR ===", text.length);
    const clean = text.replace(/```json|```/g, "").trim();

    // Parse robuste : extraire les 4 blocs JSON ind√©pendants
    try {
      return JSON.parse(clean);
    } catch(e) {
      // Si le JSON est tronqu√©, extraire ce qui est disponible champ par champ
      const extract = (key) => {
        const rx = new RegExp(`"${key}"\\s*:\\s*(\\{[\\s\\S]*?)(?=,\\s*"(?:budget|bestseller|premium|conseil|introduction)"\\s*:|\\}\\s*$)`, 'i');
        const m = clean.match(rx);
        if(!m) return null;
        try { return JSON.parse(m[1]); } catch { return null; }
      };
      const introRx = clean.match(/"introduction"\s*:\s*"([^"]+)"/);
      const conseilRx = clean.match(/"conseil"\s*:\s*"([^"]+)"/);
      const result = {
        introduction: introRx?.[1] || "",
        budget: extract("budget"),
        bestseller: extract("bestseller"),
        premium: extract("premium"),
        conseil: conseilRx?.[1] || "",
      };
      // Si un pack est manquant, on tente de le r√©g√©n√©rer
      if(!result.premium) {
        console.warn("Pack premium manquant dans la r√©ponse IA, tentative de r√©cup√©ration...");
        result._incomplet = true;
      }
      // Si pack premium manquant, appel s√©par√© pour le r√©cup√©rer
      if(!result.premium && catalogueText) {
        try {
          const promptPremium = `Tu es une experte beaut√© Mihi. G√©n√®re UNIQUEMENT le Pack Boost Premium pour ${nomClient||"cette cliente"} (${typeLabel}).

Profil cliente: ${reponsesText}

CATALOGUE MIHI:
${catalogueText}

G√©n√®re 4 √Ý 5 produits du catalogue pour un pack premium complet. R√©ponds UNIQUEMENT avec ce JSON (rien d'autre):
{"nom":"üöÄ Pack Boost Premium","total":"XX.XX‚Ç¨","produits":[{"nom":"Nom FR","prix":"XX.XX‚Ç¨","usage":"Matin/Soir","benefice":"1 phrase"}],"routine":"1 phrase"}`;
          const r2 = await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","x-api-key":"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","anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},body:JSON.stringify({model:"claude-sonnet-4-6",max_tokens:1500,messages:[{role:"user",content:promptPremium}]})});
          const d2 = await r2.json();
          const t2 = d2.content?.map(i=>i.text||"").join("").replace(/```json|```/g,"").trim();
          result.premium = JSON.parse(t2);
        } catch(e2) { console.warn("R√©cup√©ration pack premium √©chou√©e:", e2); }
      }
      return result;
    }
  } catch (fetchErr) {
    console.error("Erreur r√©seau / fetch:", fetchErr);
    throw fetchErr;
  }
}

