// Note interne pour la distributrice : pas de tags dans ce quiz, on d√©rive le levier
// conseill√© √Ý partir des questions q4 (r√©seaux) et q5 (bouche-√Ý-oreille)
function getRecrutementInternalNote(reponses, level){
  const scoreVal = (qid, v) => {
    const q = QUIZ_RECRUTEMENT.find(x=>x.id===qid);
    const opt = q?.options.find(o=>o.value===v);
    return opt?.score || 0;
  };
  const scoreReseaux = scoreVal("q4", reponses.q4);
  const scoreBouche = scoreVal("q5", reponses.q5);

  let levier, action;
  if(scoreReseaux>=3 && scoreBouche>=3){
    levier = "Mix r√©seaux + bouche-√Ý-oreille ‚Äî cette personne est √Ý l'aise sur les deux canaux.";
    action = "Propose un d√©marrage sur les deux fronts : entourage proche en premier (conversion plus rapide), r√©seaux sociaux en parall√®le pour construire sa visibilit√©.";
  } else if(scoreReseaux>=3){
    levier = "R√©seaux sociaux ‚Äî c'est le canal le plus naturel pour cette personne.";
    action = "Oriente-la vers le programme MOCHA pour structurer sa pr√©sence sur les r√©seaux d√®s le d√©part.";
  } else if(scoreBouche>=3){
    levier = "Bouche-√Ý-oreille / entourage ‚Äî c'est le canal le plus naturel pour cette personne.";
    action = "Aide-la √Ý construire sa liste de contacts proches et donne-lui des scripts de conversation simples pour parler naturellement de son activit√©.";
  } else {
    levier = "Aucun canal naturel identifi√© pour l'instant ‚Äî accompagnement rapproch√© n√©cessaire.";
    action = "Avant de parler de canal, prends un temps pour explorer avec elle o√π elle se sent le plus √Ý l'aise. Propose un test cadr√© sur 2 semaines (1 semaine r√©seaux, 1 semaine entourage).";
  }

  if(level<=1){
    action += " Vu son niveau de motivation actuel, ne mets aucune pression ‚Äî reste disponible sans insister.";
  } else if(level>=4){
    action += " Et n'h√©site pas √Ý lui parler rapidement de la dimension √©quipe/leadership.";
  }

  return {levier, action};
}

